const express = require('express');
const multer = require('multer');
const app = express();

const storage = multer.diskStorage({
  destination: (req, file, cb) => cb(null, 'uploads/'),
  filename: (req, file, cb) => cb(null, Date.now() + '_' + file.originalname)
});

const maxSize = 50 * 1024; // 50 KB in bytes

const upload = multer({
  storage,
  limits: { fileSize: maxSize }
});

app.get('/', (req, res) => {
  res.send(`
    <form action='/upload' method='POST' enctype='multipart/form-data'>
      <input type='file' name='anyfile' /><br><br>
      <input type='submit' value='Upload (Max 50KB)' />
    </form>
  `);
});

app.post('/upload', (req, res) => {
  upload.single('anyfile')(req, res, (err) => {
    if (err instanceof multer.MulterError && err.code === 'LIMIT_FILE_SIZE') {
      return res.send('<h2 style="color:red;">File too large! Max allowed size is 50KB.</h2>');
    } else if (err) {
      return res.send(`<h2>Error: ${err.message}</h2>`);
    }
    res.send(`<h2>File uploaded successfully: ${req.file.originalname}</h2>`);
  });
});

app.listen(3000, () => console.log('Server on port 3000'));

const express = require('express');
const multer = require('multer');
const path = require('path');
const app = express();

// Configure diskStorage
const storage = multer.diskStorage({
  destination: function(req, file, cb) {
    cb(null, 'uploads/'); // Files stored in 'uploads' directory
  },
  filename: function(req, file, cb) {
    // Unique filename: timestamp + original extension
    const uniqueName = Date.now() + path.extname(file.originalname);
    cb(null, uniqueName);
  }
});

// Create multer instance
const upload = multer({ storage: storage });

app.get('/', (req, res) => {
