});

// Route to handle upload - upload.single('fieldname')
app.post('/upload', upload.single('userFile'), (req, res) => {
  res.send(`File '${req.file.originalname}' uploaded to /uploads/ as '${req.file.filename}'`);
});

app.listen(3000, () => console.log('Server running on port 3000'));
