// Install: npm install express multer sharp
const express = require('express');
const multer = require('multer');
const sharp = require('sharp');
const path = require('path');
const fs = require('fs');
const app = express();

// Use memory storage so we can process the buffer with sharp
const upload = multer({ storage: multer.memoryStorage() });

// Ensure output directories exist
['small','medium','large'].forEach(size => {
  if (!fs.existsSync(`uploads/${size}`)) fs.mkdirSync(`uploads/${size}`, { recursive: true });
});

app.get('/', (req, res) => {
  res.send(`
    <form action='/upload' method='POST' enctype='multipart/form-data'>
      <input type='file' name='image' accept='image/*' /><br><br>
      <input type='submit' value='Upload & Resize' />
    </form>
  `);
});

app.post('/upload', upload.single('image'), async (req, res) => {
  if (!req.file) return res.send('No image uploaded');
  const filename = Date.now();
  const ext = '.jpg';

  await sharp(req.file.buffer).resize(100, 100).toFile(`uploads/small/${filename}${ext}`);
  await sharp(req.file.buffer).resize(300, 300).toFile(`uploads/medium/${filename}${ext}`);
  await sharp(req.file.buffer).resize(800, 800).toFile(`uploads/large/${filename}${ext}`);

  res.send(`<h2>Image saved in 3 sizes: small(100x100), medium(300x300), large(800x800)</h2>`);
});

app.listen(3000, () => console.log('Server on port 3000'));

