// Install: npm install express nodemailer
const express = require('express');
const nodemailer = require('nodemailer');
const app = express();

// Create transporter (using Gmail as example)
const transporter = nodemailer.createTransport({
  service: 'gmail',
  auth: {
    user: 'sender@gmail.com',       // Your email
    pass: 'your_app_password'        // App password (not normal password)
  }
});

app.get('/', (req, res) => {
  // Mail options
  const mailOptions = {
    from: 'sender@gmail.com',
    to: 'recipient@gmail.com',
    subject: 'Automatic Email from Node.js',
    text: 'Hello! This is an automatic email sent from Express.js using Nodemailer.',
    html: '<h2>Hello!</h2><p>This is an <b>automatic email</b> sent from Express.js using Nodemailer.</p>'
  };

  // Send mail
  transporter.sendMail(mailOptions, (error, info) => {
    if (error) {
      console.log('Error:', error);
      res.send('<h2>Error sending email: ' + error.message + '</h2>');
    } else {
      console.log('Email sent: ' + info.response);
      res.send('<h2>Email sent successfully to recipient@gmail.com!</h2>');
    }
  });
});

app.listen(3000, () => console.log('Server on port 3000'));

