  service: 'gmail',  // Email service provider
  auth: {
    user: 'youremail@gmail.com',    // Sender's email
    pass: 'your_app_password'       // App-specific password
  }
});

app.get('/', (req, res) => {
  res.send(`
    <form action='/send' method='POST'>
      To: <input type='email' name='to' /><br>
      Subject: <input type='text' name='subject' /><br>
      Message: <textarea name='message'></textarea><br>
      <input type='submit' value='Send Email' />
    </form>
  `);
});

// Step 3: Define mail options and send
app.post('/send', (req, res) => {
  const { to, subject, message } = req.body;

  const mailOptions = {
    from: 'youremail@gmail.com',
    to: to,
    subject: subject,
    text: message
  };

  transporter.sendMail(mailOptions, (error, info) => {
    if (error) {
      res.send('Error: ' + error.message);
    } else {
      res.send('Email sent successfully! Message ID: ' + info.messageId);
